-- BLOCO 1 (parte 1/6) — Revisão linguística pílulas PI (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Mudei. Nem tudo se mudou comigo.", "tension_label": "Eu ↔ Pertencimento"}, "m2": {"scene": "Marina mudou 800 km para o norte por causa da saúde da mãe. Na quarta manhã, ela ficou sentada no carro estacionado em frente à janela da mãe por vinte minutos. Só sentada. A mãe estava lá dentro, finalmente estável. Marina tinha tomado a decisão certa.\n\nMas a mãe também a havia criado para ser independente, para construir a própria vida, para não ficar pairando. As amigas de faculdade estavam a 800 km. O trabalho era totalmente remoto agora.\n\nMarina observava as pessoas passando em frente ao prédio — vizinhos, estranhos, pessoas com vidas atadas àquele lugar.", "question": "O que Marina estava realmente esperando, sentada naquele carro?"}, "m4": {"question": "O que você notou em si mesmo respondendo isso?", "instruction": "Uma frase basta. Escreva o que ficou com você — uma palavra, uma imagem, uma sensação."}, "m3_1": {"context": "Revela se a pessoa tende a uma mudança externa (o lugar é errado) ou a uma reconciliação interna (eu não me encaixo). Específico de PI porque endereça se a tensão se resolve para fora ou para dentro.", "question": "Quando algo da sua vida atual não está funcionando, onde você naturalmente começa a olhar primeiro — no que precisa mudar neste lugar, ou no que talvez precise mudar em você?", "pole_left": "Ajustar a situação", "pole_right": "Ajustar quem eu sou aqui"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Não me envolvo.", "followup": "Sua integridade diante dessa pessoa. A chance dela conhecer seus valores. Clareza sobre se você pertence ao lado dela.", "followup_type": "cost"}, {"key": "B", "text": "Falo direto.", "followup": "Certeza de que ela vai entender. A segurança da sua posição. Possivelmente o vínculo em si.", "followup_type": "cost"}, {"key": "C", "text": "Encontro um terceiro caminho — toco no assunto, mas como pergunta, não como julgamento.", "followup": "O que esse terceiro caminho te custa?", "followup_type": "question"}, {"key": "D", "text": "Preciso de mais contexto — pergunto a outras pessoas antes de decidir.", "followup": "O que você está realmente buscando nesse contexto?", "followup_type": "question"}], "scenario": "Alguém próximo de você está fazendo algo que você considera errado. Não é ilegal. Mas vai contra o que você acredita. Essa pessoa não sabe que você sabe. Há um custo real em qualquer direção."}, "m3_3": {"q1": "Lembre de um momento em que você sabia claramente o que precisava fazer e fez, mesmo sendo difícil.", "q2": "O que tornou possível agir naquele momento?", "scoring_note": "Buscar: Qual foi o conhecimento ou clareza específica? (Pergunta de pertencimento: Era clareza sobre o que precisava pertencer, ou clareza sobre o que precisava soltar?) O que tornou a ação possível? (Permissão interna? Confiança de outra pessoa? Necessidade externa? Algo no entendimento de si?) L1.3 transversal: Testar se padrões de qualidade são herdados ou contextuais.", "q_transversal": "Naquele momento — a régua que você usou pra dizer 'tá bom assim' veio do lugar de onde você veio, ou do lugar onde você está agora?"}}$rdwth_final$::jsonb
WHERE id = '033033c4-3ec7-41b0-a687-c82bcd5a05e2';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Estou aqui agora. Mas a pessoa que eu era antes não cabe mais.", "tension_label": "Eu ↔ Pertencimento"}, "m2": {"scene": "Thiago pegou o contrato de obra a três estados de distância — pagava bem, ele precisava da estabilidade. A família ficou. Nos fins de semana, dirigia seis horas para ser o pai que conhecia os professores dos filhos, o marido que ainda ajudava com a casa. Os outros cinco dias, construía habilidade e reputação na obra — chegava firme, confiável, um estranho.\n\nNa moradia provisória, esquentava marmita no micro-ondas e dormia ao som de coisas desconhecidas. A equipe não sabia da vida que ele mantinha em outra cidade todo fim de semana. Só sabiam que ele aparecia pronto pra trabalhar.\n\nNuma quinta à noite, o caçula ligou: 'Quando você volta pra casa?' Casa — o lugar onde ele de fato morava.", "question": "Do que Thiago tinha medo se admitisse a diferença entre suas duas vidas?"}, "m4": {"question": "Conforme você passou por essas situações, do que mais teve medo de admitir?", "instruction": "Diga, em palavras, o que foi difícil admitir. Uma frase. Você não precisa resolver — só nomear."}, "m3_1": {"context": "Testa se a pessoa atribui o não-pertencimento a um descompasso externo ou a uma desorientação interna.", "question": "Quando você percebe que não se encaixa em algum lugar que parecia que devia funcionar, o que parece mais verdade — que este lugar não é certo pra mim, ou que eu ainda não encontrei meu lugar nele?", "pole_left": "Este lugar não é certo pra mim", "pole_right": "Eu ainda não encontrei meu lugar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Falo pra ela que vale a pena ficar. Construir algo. Confiar no processo.", "followup": "O direito dela ir embora enquanto ainda é simples. Saber se você está convencendo ela ou a si mesmo.", "followup_type": "cost"}, {"key": "B", "text": "Falo pra ela ficar — e me comprometo a ajudar a construir algo que faça valer a pena ficar.", "followup": "Assumir responsabilidade pelo pertencimento de outra pessoa. Descobrir se suas razões pra ficar são fortes o suficiente pras duas.", "followup_type": "cost"}, {"key": "C", "text": "Falo a verdade: vale alguma coisa, mas não tudo. Depende do que você está disposta a perder.", "followup": "O que te fez decidir oferecer essa honestidade específica?", "followup_type": "question"}, {"key": "D", "text": "Falo pra ela ir embora. Sair agora, antes que custe mais.", "followup": "A possibilidade de ficar ter sido o certo pra ela. Seu próprio compromisso com este lugar.", "followup_type": "cost"}], "scenario": "Você está na sua nova situação tempo suficiente pra entender as regras melhor que muita gente. Alguém pede sua avaliação honesta: vale ficar aqui, ou é melhor sair agora antes de se apegar mais?\n\nVocê sabe algo que ela não sabe. Está começando a pertencer aqui — mas também está vendo o custo do pertencimento mais claramente. Sua resposta vai afetar a escolha dela. E a escolha dela vai afetar se ficar aí parece compromisso ou isolamento."}, "m3_3": {"q1": "Quando você se sentiu mais você num lugar onde não esperava pertencer?", "q2": "O que era diferente em como você apareceu lá?", "scoring_note": "Revela se o pertencimento é ativado por condições externas ou permissão interna. Se respondem 'as pessoas eram diferentes' vs. 'parei de tentar me encaixar' — respostas diferentes apontam estratégias diferentes de resolução. L1.3 transversal: testar se a barra interna de qualidade foi rebaixada/ajustada para o novo contexto.", "q_transversal": "Quando você apareceu diferente naquele lugar — o que você levou foi bom o suficiente pra esse contexto novo, ou ainda estava medindo pelo padrão antigo?"}}$rdwth_final$::jsonb
WHERE id = 'e32dfcce-3202-4399-94a1-f0bfd5624f50';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Tudo mudou de lugar. Ainda estou descobrindo onde pertenço.", "tension_label": "Eu ↔ Pertencimento"}, "m2": {"scene": "Sara saiu da cidadezinha onde a família dela morava há três gerações. Estudou na capital e ficou.\n\nQuando voltou pro Natal, nada se encaixava do mesmo jeito. As ruas pareciam estreitas. Os pais perguntavam sobre a vida dela de um jeito que parecia perguntar por que tinha ido embora.\n\nNa última noite, Sara sentou com a mãe na cozinha — a mesma cozinha, os mesmos gestos, o mesmo cheiro. Mas Sara não achava as palavras pra explicar a pessoa que estava virando pra pessoa que a tinha criado.", "question": "O que Sara estava protegendo ao ficar quieta sobre quem estava virando?"}, "m4": {"question": "Quando você se imaginou nessas situações, quem você estava tentando ser — você como é hoje, ou você como acha que deveria ser?", "instruction": "Em uma frase: qual das duas parecia mais familiar, não qual era verdade."}, "m3_1": {"context": "Revela se a pessoa localiza a tensão na decisão em si ou no timing da decisão.", "question": "Quando você está fazendo algo que esperava querer fazer, mas parece oco, sua cabeça vai primeiro pra onde — pensar se fez o movimento errado, ou se mexeu antes de estar pronto?", "pole_left": "Fiz o movimento errado", "pole_right": "Eu não estava pronto pra mexer"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Volto. Família vem primeiro. Sempre posso tentar de novo depois.", "followup": "A coisa específica que você está construindo onde está. A pessoa que está virando lá. A resposta sobre se você consegue fazer dar certo.", "followup_type": "cost"}, {"key": "B", "text": "Reflito com cuidado: do que eu sou responsável? Onde minha obrigação termina e a capacidade deles começa? O que eu estaria ensinando a eles ao não voltar?", "followup": "O que essa reflexão te disse?", "followup_type": "question"}, {"key": "C", "text": "Negocio: volto por um tempo definido, com data pra terminar.", "followup": "O que faz um prazo parecer permissão em vez de adiamento?", "followup_type": "question"}, {"key": "D", "text": "Fico e estabeleço um limite claro: posso visitar, mas não posso voltar.", "followup": "Ser o responsável. A aprovação da família. Saber se você está sendo corajoso ou só fugindo.", "followup_type": "cost"}], "scenario": "Seus pais/família te pedem pra voltar. Não pra visita. Permanente. Eles precisam de você. Ou sentem sua falta. Ou estão em dificuldade. É enquadrado como necessidade, mesmo quando também é perda.\n\nVocê começou a construir algo onde está. Ainda não está estável. Pode falhar. Mas é seu. A coisa pra qual eles querem que você volte é segura — é conhecida. E eles não estão errados em precisar de você."}, "m3_3": {"q1": "Lembre de uma vez em que você aceitou que algo de antes não podia vir junto, e isso na verdade trouxe alívio.", "q2": "Como você soube que estava tudo bem soltar?", "scoring_note": "Testa se conseguem distinguir entre o que tiveram que perder e o que escolheram deixar pra trás. A capacidade de diferenciar é chave para resolver tensão PI. L1.3 transversal: testar critérios de suficiência para conclusão antes do desapego.", "q_transversal": "Quando você soltou aquilo — você sabia que tinha feito o suficiente, ou ficou achando que devia ter feito mais?"}}$rdwth_final$::jsonb
WHERE id = 'c7a02d20-2bef-479c-b00c-4e7d7169e6de';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Cheguei. Ainda esperando o resto de mim me alcançar.", "tension_label": "Eu ↔ Pertencimento"}, "m2": {"scene": "A carreira de Daniel exigia mudança a cada três anos. Aos 32, já tinha morado em onze lugares. Era bom em chegar, achar o bairro certo, se estabelecer profissionalmente em poucas semanas.\n\nO que ele não contava pra ninguém: não tinha foto nas paredes do apartamento. Os pais tinham se aposentado num lugar onde ele nunca tinha morado.\n\nNum evento de networking, alguém perguntou: 'De onde você é?' Daniel respondeu com o cargo, as responsabilidades, a expertise. Foi uma resposta excelente. Enquanto dizia, percebeu que tinha feito de propósito.", "question": "O que Daniel ganhava sendo a pessoa que não precisava de um lugar pra pertencer?"}, "m4": {"question": "Se você tivesse que descrever em uma frase o que pertencer realmente significa pra você — não o que devia significar, mas o que de fato significa pra você — qual seria essa frase?", "instruction": "Escreva a frase. Foi alívio ou exposição escrever?"}, "m3_1": {"context": "Revela onde está o custo do pertencimento — no apego ao passado ou no investimento no novo.", "question": "Se você tivesse que escolher agora entre voltar pro lugar de onde veio ou se comprometer mais plenamente onde está, qual seria a escolha mais difícil?", "pole_left": "Voltar seria mais difícil", "pole_right": "Ficar plenamente seria mais difícil"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Reconecto plenamente. Parece recuperar parte da vida antiga.", "followup": "Testar se a versão antiga de você ainda existe. A simplicidade de ser novo aqui.", "followup_type": "cost"}, {"key": "B", "text": "Sou cordial mas mantenho limites claros.", "followup": "A possibilidade de uma reconexão real. Saber se você de fato mudou ou só ficou melhor em encenar a mudança.", "followup_type": "cost"}, {"key": "C", "text": "Sou honesto: não sei mais quem eu sou pra você. Podemos descobrir?", "followup": "O que fez a honestidade parecer mais segura que a distância?", "followup_type": "question"}, {"key": "D", "text": "Sigo a energia que ela traz.", "followup": "O que você estava testando ao seguir a energia dela?", "followup_type": "question"}], "scenario": "Seu passado está te alcançando. Alguém de antes da sua mudança está na sua nova cidade a trabalho. Ou se mudando pra cá. Ou perguntando se você quer reconectar.\n\nEssa pessoa te conhece de quando você estava lá. Ela tem uma versão de você que era real. E ela também é diferente — ela mudou. Mas você está preocupado que ela vá te segurar na versão antiga como espelho. Também está preocupado que tenha virado um estranho pra ela."}, "m3_3": {"q1": "Lembre de um momento em que percebeu que não era mais a mesma pessoa de quando chegou em algum lugar novo. Como foi esse momento?", "q2": "Você sentiu que tinha perdido algo, ganhado algo, ou os dois?", "scoring_note": "Endereça diretamente a tensão do M1 (nem tudo veio comigo). A resposta revela se está em luto, adaptando ou integrando. L1.3 transversal: testar se padrões de qualidade evoluíram junto com a identidade.", "q_transversal": "Naquela percepção de mudança — o que você considerava 'estar indo bem' também mudou com você?"}}$rdwth_final$::jsonb
WHERE id = '6bd6d17d-a5d2-4882-9544-359d27a07ef6';